     1→/**
     2→ * Error Boundaries — production-grade failure containment
     3→ *
     4→ * Exports:
     5→ * • AppErrorBoundary   — root-level, full-screen fallback, chunk-aware
     6→ * • ErrorBoundary      — alias for AppErrorBoundary (backwards compat)
     7→ * • ScreenErrorBoundary — per-screen, in-place fallback, nav-safe
     8→ * • InlineErrorFallback — static inline widget fallback
     9→ */
    10→
    11→import React, { Component, ErrorInfo, ReactNode } from 'react';
    12→import { AlertTriangle, RefreshCw, Home, RotateCcw, Trash2 } from 'lucide-react';
    13→import { errorLogger } from '../../utils/errorLogger';
    14→import { clearAllCaches } from '../../utils/cacheGuard';
    15→
    16→// ── Helpers ───────────────────────────────────────────────────────────────────
    17→
    18→function isChunkError(error: Error): boolean {
    19→  const msg  = error.message?.toLowerCase() ?? '';
    20→  const name = error.name?.toLowerCase()    ?? '';
    21→  return (
    22→    name === 'chunkloaderror' ||
    23→    msg.includes('loading chunk') ||
    24→    msg.includes('loading css chunk') ||
    25→    msg.includes('dynamically imported module') ||
    26→    (msg.includes('failed to fetch') && (msg.includes('.js') || msg.includes('chunk')))
    27→  );
    28→}
    29→
    30→// ─────────────────────────────────────────────────────────────────────────────
    31→// ROOT ERROR BOUNDARY  (Module 1)
    32→// Full-screen fallback, chunk detection, safe recovery actions
    33→// ─────────────────────────────────────────────────────────────────────────────
    34→
    35→interface RootProps {
    36→  children : ReactNode;
    37→  fallback?: ReactNode;
    38→}
    39→interface RootState {
    40→  hasError  : boolean;
    41→  isChunk   : boolean;
    42→  error    ?: Error;
    43→}
    44→
    45→export class AppErrorBoundary extends Component<RootProps, RootState> {
    46→  public state: RootState = { hasError: false, isChunk: false };
    47→
    48→  public static getDerivedStateFromError(error: Error): RootState {
    49→    return {
    50→      hasError : true,
    51→      isChunk  : isChunkError(error),
    52→      error,
    53→    };
    54→  }
    55→
    56→  public componentDidCatch(error: Error, info: ErrorInfo): void {
    57→    errorLogger.log('render', error, { componentStack: info.componentStack?.slice(0, 400) }, 'AppErrorBoundary');
    58→  }
    59→
    60→  private handleRetry = () => {
    61→    this.setState({ hasError: false, isChunk: false, error: undefined });
    62→  };
    63→
    64→  private handleDashboard = () => {
    65→    window.location.hash = '#/';
    66→    window.location.reload();
    67→  };
    68→
    69→  private handleFullReset = () => {
    70→    try { clearAllCaches(); } catch {}
    71→    window.location.hash = '#/';
    72→    window.location.reload();
    73→  };
    74→
    75→  public render() {
    76→    if (!this.state.hasError) return this.props.children;
    77→    if (this.props.fallback)  return this.props.fallback;
    78→
    79→    const { isChunk } = this.state;
    80→
    81→    return (
    82→      <div
    83→        className="flex h-screen items-center justify-center flex-col p-6 text-center"
    84→        style={{ background: '#0b0e1a' }}
    85→      >
    86→        <div className="max-w-xs w-full">
    87→
    88→          {/* Icon */}
    89→          <div
    90→            className="w-20 h-20 mx-auto mb-6 rounded-full flex items-center justify-center"
    91→            style={{ background: isChunk ? 'rgba(99,102,241,0.15)' : 'rgba(239,68,68,0.12)', border: `1px solid ${isChunk ? 'rgba(99,102,241,0.3)' : 'rgba(239,68,68,0.25)'}` }}
    92→          >
    93→            <AlertTriangle
    94→              className="w-10 h-10"
    95→              style={{ color: isChunk ? '#818cf8' : '#f87171' }}
    96→            />
    97→          </div>
    98→
    99→          {/* Heading */}
   100→          <h1 className="text-xl font-black mb-2" style={{ color: 'rgba(240,244,255,0.95)' }}>
   101→            {isChunk ? 'Update Available' : 'Something went wrong'}
   102→          </h1>
   103→
   104→          {/* Body */}
   105→          <p className="text-sm mb-8 leading-relaxed" style={{ color: 'rgba(148,163,184,0.7)' }}>
   106→            {isChunk
   107→              ? "A newer version of the app is ready. Reload to get the latest updates."
   108→              : "An unexpected error occurred. Your data is safe — please try one of the options below."}
   109→          </p>
   110→
   111→          {/* Actions */}
   112→          <div className="flex flex-col gap-3">
   113→            {isChunk ? (
   114→              <button
   115→                onClick={() => window.location.reload()}
   116→                className="w-full py-3.5 px-4 rounded-2xl font-black text-sm flex items-center justify-center gap-2 active:scale-95 transition-transform"
   117→                style={{ background: 'linear-gradient(135deg,#6366f1,#4f46e5)', color: '#fff', boxShadow: '0 4px 20px rgba(99,102,241,0.4)' }}
   118→              >
   119→                <RefreshCw size={16} />
   120→                Reload App
   121→              </button>
   122→            ) : (
   123→              <>
   124→                <button
   125→                  onClick={this.handleRetry}
   126→                  className="w-full py-3.5 px-4 rounded-2xl font-black text-sm flex items-center justify-center gap-2 active:scale-95 transition-transform"
   127→                  style={{ background: 'linear-gradient(135deg,#6366f1,#4f46e5)', color: '#fff', boxShadow: '0 4px 20px rgba(99,102,241,0.35)' }}
   128→                >
   129→                  <RotateCcw size={16} />
   130→                  Try Again
   131→                </button>
   132→
   133→                <button
   134→                  onClick={this.handleDashboard}
   135→                  className="w-full py-3.5 px-4 rounded-2xl font-black text-sm flex items-center justify-center gap-2 active:scale-95 transition-transform"
   136→                  style={{ background: 'rgba(255,255,255,0.07)', border: '1px solid rgba(255,255,255,0.1)', color: 'rgba(240,244,255,0.85)' }}
   137→                >
   138→                  <Home size={16} />
   139→                  Go to Dashboard
   140→                </button>
   141→
   142→                <button
   143→                  onClick={this.handleFullReset}
   144→                  className="w-full py-3 px-4 rounded-2xl font-bold text-xs flex items-center justify-center gap-2 active:scale-95 transition-transform"
   145→                  style={{ background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.15)', color: 'rgba(248,113,113,0.7)' }}
   146→                >
   147→                  <Trash2 size={13} />
   148→                  Clear Cache &amp; Restart
   149→                </button>
   150→              </>
   151→            )}
   152→          </div>
   153→        </div>
   154→      </div>
   155→    );
   156→  }
   157→}
   158→
   159→/** Backwards-compatible alias — main.tsx uses `<ErrorBoundary>` */
   160→export const ErrorBoundary = AppErrorBoundary;
   161→
   162→// ─────────────────────────────────────────────────────────────────────────────
   163→// SCREEN ERROR BOUNDARY  (Module 2)
   164→// Per-screen, in-place fallback.  Keyed by activeTab so it auto-resets on
   165→// navigation.  Bottom nav and global shell remain fully functional.
   166→// ─────────────────────────────────────────────────────────────────────────────
   167→
   168→interface ScreenProps {
   169→  children               : ReactNode;
   170→  /** Called when user taps "Go to Dashboard" */
   171→  onNavigateToDashboard ?: () => void;
   172→  /** Optional screen name shown in the fallback */
   173→  screenName            ?: string;
   174→}
   175→interface ScreenState {
   176→  hasError : boolean;
   177→  isChunk  : boolean;
   178→  error   ?: Error;
   179→}
   180→
   181→export class ScreenErrorBoundary extends Component<ScreenProps, ScreenState> {
   182→  public state: ScreenState = { hasError: false, isChunk: false };
   183→
   184→  public static getDerivedStateFromError(error: Error): ScreenState {
   185→    return { hasError: true, isChunk: isChunkError(error), error };
   186→  }
   187→
   188→  public componentDidCatch(error: Error, info: ErrorInfo): void {
   189→    errorLogger.log(
   190→      'render', error,
   191→      { screen: this.props.screenName, componentStack: info.componentStack?.slice(0, 300) },
   192→      'ScreenErrorBoundary',
   193→    );
   194→  }
   195→
   196→  private handleRetry = () => {
   197→    this.setState({ hasError: false, isChunk: false, error: undefined });
   198→  };
   199→
   200→  private handleDashboard = () => {
   201→    this.setState({ hasError: false, isChunk: false, error: undefined });
   202→    this.props.onNavigateToDashboard?.();
   203→  };
   204→
   205→  public render() {
   206→    if (!this.state.hasError) return this.props.children;
   207→
   208→    const { isChunk, error } = this.state;
   209→    const screen = this.props.screenName ?? 'this screen';
   210→
   211→    // Chunk error: prompt reload
   212→    if (isChunk) {
   213→      return (
   214→        <div className="flex flex-col h-full items-center justify-center p-8 text-center" style={{ background: '#0b0e1a' }}>
   215→          <div
   216→            className="w-14 h-14 rounded-2xl flex items-center justify-center mb-4"
   217→            style={{ background: 'rgba(99,102,241,0.15)', border: '1px solid rgba(99,102,241,0.3)' }}
   218→          >
   219→            <RefreshCw className="w-7 h-7" style={{ color: '#818cf8' }} />
   220→          </div>
   221→          <p className="font-black text-base mb-1" style={{ color: 'rgba(240,244,255,0.9)' }}>Update Available</p>
   222→          <p className="text-xs mb-6" style={{ color: 'rgba(148,163,184,0.6)' }}>
   223→            A newer version of this screen is ready.
   224→          </p>
   225→          <button
   226→            onClick={() => window.location.reload()}
   227→            className="px-6 py-3 rounded-2xl font-black text-sm active:scale-95 transition-transform"
   228→            style={{ background: 'linear-gradient(135deg,#6366f1,#4f46e5)', color: '#fff' }}
   229→          >
   230→            Reload App
   231→          </button>
   232→        </div>
   233→      );
   234→    }
   235→
   236→    // Normal render error
   237→    return (
   238→      <div className="flex flex-col h-full items-center justify-center p-8 text-center" style={{ background: '#0b0e1a' }}>
