     1→import React, { createContext, useContext, useState, useCallback, useEffect, ReactNode } from 'react';
     2→import { User } from 'firebase/auth';
     3→import { AppSettings } from '../types';
     4→import { DEFAULT_SETTINGS } from '../config/constants';
     5→
     6→// Unified App State
     7→interface AppState {
     8→  user: User | null;
     9→  appSettings: AppSettings;
    10→  activeTab: string;
    11→  isOnline: boolean;
    12→  pendingSync: number;
    13→}
    14→
    15→interface AppContextType {
    16→  state: AppState;
    17→  setUser: (user: User | null) => void;
    18→  setAppSettings: (settings: AppSettings) => void;
    19→  updateAppSettings: (partial: Partial<AppSettings>) => void;
    20→  setActiveTab: (tab: string) => void;
    21→  setOnlineStatus: (online: boolean) => void;
    22→  incrementPendingSync: () => void;
    23→  decrementPendingSync: () => void;
    24→}
    25→
    26→const AppContext = createContext<AppContextType | null>(null);
    27→
    28→export const AppContextProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    29→  const [state, setState] = useState<AppState>({
    30→    user: null,
    31→    appSettings: DEFAULT_SETTINGS,
    32→    activeTab: 'dashboard',
    33→    // FIX: initialise from navigator.onLine (unchanged), but also subscribe to
    34→    // window online/offline events so isOnline tracks the real network state
    35→    // instead of being a stale snapshot taken only at app startup.
    36→    isOnline: navigator.onLine,
    37→    pendingSync: 0,
    38→  });
    39→
    40→  // FIX: Keep isOnline in sync with actual connectivity events.
    41→  useEffect(() => {
    42→    const handleOnline  = () => setState(prev => ({ ...prev, isOnline: true  }));
    43→    const handleOffline = () => setState(prev => ({ ...prev, isOnline: false }));
    44→
    45→    window.addEventListener('online',  handleOnline);
    46→    window.addEventListener('offline', handleOffline);
    47→
    48→    return () => {
    49→      window.removeEventListener('online',  handleOnline);
    50→      window.removeEventListener('offline', handleOffline);
    51→    };
    52→  }, []);
    53→
    54→  const setUser = useCallback((user: User | null) => {
    55→    setState(prev => ({ ...prev, user }));
    56→  }, []);
    57→
    58→  const setAppSettings = useCallback((appSettings: AppSettings) => {
    59→    setState(prev => ({ ...prev, appSettings }));
    60→  }, []);
    61→
    62→  const updateAppSettings = useCallback((partial: Partial<AppSettings>) => {
    63→    setState(prev => ({
    64→      ...prev,
    65→      appSettings: { ...prev.appSettings, ...partial },
    66→    }));
    67→  }, []);
    68→
    69→  const setActiveTab = useCallback((activeTab: string) => {
    70→    setState(prev => ({ ...prev, activeTab }));
    71→  }, []);
    72→
    73→  const setOnlineStatus = useCallback((isOnline: boolean) => {
    74→    setState(prev => ({ ...prev, isOnline }));
    75→  }, []);
    76→
    77→  const incrementPendingSync = useCallback(() => {
    78→    setState(prev => ({ ...prev, pendingSync: prev.pendingSync + 1 }));
    79→  }, []);
    80→
    81→  const decrementPendingSync = useCallback(() => {
    82→    setState(prev => ({ ...prev, pendingSync: Math.max(0, prev.pendingSync - 1) }));
    83→  }, []);
    84→
    85→  return (
    86→    <AppContext.Provider
    87→      value={{
    88→        state,
    89→        setUser,
    90→        setAppSettings,
    91→        updateAppSettings,
    92→        setActiveTab,
    93→        setOnlineStatus,
    94→        incrementPendingSync,
    95→        decrementPendingSync,
    96→      }}
    97→    >
    98→      {children}
    99→    </AppContext.Provider>
   100→  );
   101→};
