     1→export type FilterPeriod = 'current_month' | 'current_year' | 'current_business_year' | 'all';
     2→
     3→export function computeDateRangeFromPeriod(
     4→  period: FilterPeriod | undefined,
     5→  financialYearStart?: string
     6→): { start: string; end: string } {
     7→  const today = new Date();
     8→  const todayStr = today.toISOString().split('T')[0];
     9→
    10→  if (!period || period === 'all') {
    11→    return { start: '', end: '' };
    12→  }
    13→
    14→  if (period === 'current_month') {
    15→    const start = new Date(today.getFullYear(), today.getMonth(), 1)
    16→      .toISOString()
    17→      .split('T')[0];
    18→    return { start, end: todayStr };
    19→  }
    20→
    21→  if (period === 'current_year') {
    22→    const start = `${today.getFullYear()}-01-01`;
    23→    return { start, end: todayStr };
    24→  }
    25→
    26→  if (period === 'current_business_year') {
    27→    // Parse financial year start month (e.g. "April" => 4, default to 4 for India)
    28→    let fyMonth = 4; // April = month 4 (1-indexed)
    29→    if (financialYearStart) {
    30→      const monthMap: Record<string, number> = {
    31→        january: 1, february: 2, march: 3, april: 4, may: 5, june: 6,
    32→        july: 7, august: 8, september: 9, october: 10, november: 11, december: 12,
    33→      };
    34→      const parsed = monthMap[financialYearStart.toLowerCase().trim()];
    35→      if (parsed) fyMonth = parsed;
    36→    }
    37→
    38→    const currentMonth = today.getMonth() + 1; // 1-indexed
    39→    const currentYear = today.getFullYear();
    40→
    41→    let fyYear: number;
    42→    if (currentMonth >= fyMonth) {
    43→      fyYear = currentYear;
    44→    } else {
    45→      fyYear = currentYear - 1;
    46→    }
    47→
    48→    const startMonth = String(fyMonth).padStart(2, '0');
    49→    const start = `${fyYear}-${startMonth}-01`;
    50→    return { start, end: todayStr };
    51→  }
    52→
    53→  return { start: '', end: '' };
    54→}
    55→
    56→export function getDefaultDateRange(settings: any): { start: string; end: string } {
    57→  const period: FilterPeriod = settings?.automation?.default_filter_period || 'all';
    58→  const financialYearStart = settings?.profile?.financial_year_start;
    59→  return computeDateRangeFromPeriod(period, financialYearStart);
    60→}
