    18→function webDownload(blob: Blob, filename: string) {
    19→  const url = URL.createObjectURL(blob);
    20→  const a = document.createElement('a');
    21→  a.href = url;
    22→  a.download = filename;
    23→  document.body.appendChild(a);
    24→  a.click();
    25→  a.remove();
    26→  setTimeout(() => URL.revokeObjectURL(url), 500);
    27→}
