    29→/**
    30→ * Web Share API — shows the native share sheet on mobile browsers that support it.
    31→ * Falls back to webDownload if not supported or if sharing fails.
    32→ */
    33→async function webShare(blob: Blob, filename: string): Promise<void> {
    34→  try {
    35→    const file = new File([blob], filename, { type: blob.type || 'application/octet-stream' });
    36→    if (
    37→      typeof navigator.share === 'function' &&
    38→      typeof navigator.canShare === 'function' &&
    39→      navigator.canShare({ files: [file] })
    40→    ) {
    41→      await navigator.share({ files: [file], title: filename });
    42→      return;
    43→    }
    44→  } catch (e: any) {
    45→    // User cancelled share or API failed — fall through to download
    46→    if (e?.name !== 'AbortError') console.warn('webShare fallback to download:', e);
    47→  }
    48→  webDownload(blob, filename);
    49→}
