    54→async function nativeShareBlob(blob: Blob, filename: string): Promise<void> {
    55→  const { Filesystem, Directory } = await import('@capacitor/filesystem');
    56→  const { Share } = await import('@capacitor/share');
    57→
    58→  // Convert blob → base64
