   128→  sharePdfBlob: async (blob: Blob, filename: string): Promise<boolean> => {
   129→    try {
   130→      if (isNative()) {
   131→        await nativeShareBlob(blob, filename);
   132→      } else {
   133→        await webShare(blob, filename);
   134→      }
