   142→      } catch (e2) {
   143→        console.error('❌ Web fallback also failed:', e2);
   144→        return false;
   145→      }
   146→    }
   147→  },
   148→
   149→  /** Save Base64 string and share/download */
   150→  saveBase64File: async (base64: string, filename: string): Promise<void> => {
   151→    try {
   152→      if (isNative()) {
   153→        const { Filesystem, Directory } = await import('@capacitor/filesystem');
   154→        const { Share } = await import('@capacitor/share');
   155→        const result = await Filesystem.writeFile({
   156→          path: filename,
   157→          data: base64,
   158→          directory: Directory.Cache,
   159→        });
   160→        let fileUri = result.uri;
   161→        if (!fileUri) {
   162→          const uriResult = await Filesystem.getUri({ path: filename, directory: Directory.Cache });
   163→          fileUri = uriResult.uri;
   164→        }
   165→        // Use files[] (not url) so WhatsApp/Drive treat this as a real document attachment.
   166→        await Share.share({ title: filename, dialogTitle: filename, files: [fileUri] });
   167→      } else {
   168→        // Web: convert base64 to blob, then try Web Share API, fallback to download
   169→        const byteChars = atob(base64);
   170→        const byteNumbers = new Array(byteChars.length);
   171→        for (let i = 0; i < byteChars.length; i++) {
   172→          byteNumbers[i] = byteChars.charCodeAt(i);
   173→        }
   174→        const blob = new Blob([new Uint8Array(byteNumbers)], { type: 'application/pdf' });
   175→        await webShare(blob, filename);
   176→      }
   177→    } catch (error) {
   178→      console.error('❌ saveBase64File failed:', error);
   179→      // Fallback: try direct data URI download
   180→      const a = document.createElement('a');
   181→      a.href = 'data:application/pdf;base64,' + base64;
   182→      a.download = filename;
   183→      a.click();
   184→    }
   185→  },
