   198→  /** Generic share or download (text content like CSV) */
   199→  shareOrDownload: async (content: string, filename: string, mimeType: string): Promise<void> => {
   200→    try {
   201→      if (isNative()) {
   202→        await nativeShareText(content, filename);
   203→      } else {
   204→        const blob = new Blob([content], { type: mimeType });
   205→        await webShare(blob, filename);
   206→      }
   207→    } catch (error) {
   208→      console.error('❌ shareOrDownload failed:', error);
   209→      const blob = new Blob([content], { type: mimeType });
   210→      webDownload(blob, filename);
   211→    }
   212→  },
   213→
   214→  /** CSV Export */
   215→  exportToCSV: async (data: any[], headers: string[], filename: string): Promise<void> => {
   216→    const rows = [
   217→      headers.join(','),
   218→      ...data.map(row => headers.map(h => {
   219→        const val = row[h] ?? '';
   220→        return `"${String(val).replace(/"/g, '""')}"`;
   221→      }).join(','))
   222→    ];
   223→    const csvContent = rows.join('\n');
   224→    await exportService.shareOrDownload(csvContent, filename, 'text/csv');
