    87→    rawSecurity.enabled ?? rawSecurity.app_lock_enabled ?? rawSecurity.appLockEnabled ?? defaults.security?.enabled ?? false;
    88→  const pin = typeof rawSecurity.pin === 'string' ? rawSecurity.pin : defaults.security?.pin || '';
    89→  const enable_biometrics = rawSecurity.enable_biometrics ?? defaults.security?.enable_biometrics ?? false;
    90→  merged.security = {
