   101→export function applyThemeToDocument(settings: AppSettings) {
   102→  const root = document.documentElement;
   103→  const theme = normalizeThemeId(settings?.preferences?.theme);
   104→  const custom = settings?.preferences?.custom_primary_hsl;
   105→
   106→  if (theme === 'custom' && custom) {
   107→    root.dataset.theme = 'custom';
   108→    root.style.setProperty('--primary', `${clamp(custom.h, 0, 360)} ${clamp(custom.s, 0, 100)}% ${clamp(custom.l, 0, 100)}%`);
